"""アプリアイコン (assets/icon.ico をコードに埋め込んだもの)。"""
from __future__ import annotations
import base64
from PySide6.QtCore import QByteArray
from PySide6.QtGui import QIcon, QPixmap

_ICO_B64 = (
    ""
)

def app_icon() -> QIcon:
    """assets/icon.ico から生成した QIcon を返す。"""
    data = base64.b64decode(_ICO_B64)
    pix = QPixmap()
    pix.loadFromData(QByteArray(data))
    return QIcon(pix)
